#include <stdio.h>
#include <stdlib.h>

/* Public module declarations simulating separate compilation principles */
typedef int (*operation_cb)(int, int);

/* Static Helper: internal linkage, hidden from global scope */
static void log_execution(const char *op_name) {
    printf("[LOG] Executing operation: %s\n", op_name);
}

/* Public interface functions */
inline int add_operation(int a, int b) {
    return a + b;
}

inline int multiply_operation(int a, int b) {
    return a * b;
}

/* High-order dynamic engine taking a callback */
void run_engine(int val1, int val2, operation_cb callback, const char *name) {
    log_execution(name);
    if (callback == NULL) {
        printf("Error: Callback pointer is NULL!\n");
        return;
    }
    int result = callback(val1, val2);
    printf("Result of %s: %d\n", name, result);
}

int main(void) {
    /* Assign operations to function pointers */
    operation_cb op_ptr = add_operation;

    printf("--- Executing with Dynamic Function Pointers ---\n");
    run_engine(15, 30, op_ptr, "Addition");

    op_ptr = multiply_operation;
    run_engine(5, 6, op_ptr, "Multiplication");

    return 0;
}

