#include <stdio.h>
#include <stdint.h>

/* Simulation of a hardware memory-mapped register */
static volatile uint32_t simulated_status_reg = 0x00;

/* High-performance vector copy using 'restrict' to promise no aliasing */
void optimized_add(int * restrict dest, const int * restrict src, int val, int size) {
    for (int i = 0; i < size; i++) {
        dest[i] = src[i] + val;
    }
}

void run_vla_demo(int dynamic_size) {
    printf("Allocating dynamic-size VLA on stack of size: %d\n", dynamic_size);
    int stack_vla[dynamic_size]; /* Dynamic size VLA */

    for(int i = 0; i < dynamic_size; i++) {
        stack_vla[i] = i * 10;
    }

    int destination_array[10];
    optimized_add(destination_array, stack_vla, 5, dynamic_size);

    for(int i = 0; i < dynamic_size; i++) {
        printf("dest[%d] = %d\n", i, destination_array[i]);
    }
}

int main(void) {
    /* Simulate monitoring of status register */
    simulated_status_reg = 0x01;
    if (simulated_status_reg != 0x00) {
        printf("Hardware peripheral active, executing VLA calculations...\n");
        run_vla_demo(5);
    }
    return 0;
}

