#define STACK_THRESHOLD 1024

void safe_process(int N) {
    if (N <= 0) return;
    int *work_buffer = NULL;
    int is_heap = 0;

    if (N < STACK_THRESHOLD) {
        /* Use standard VLA safely on stack */
        int temp_vla[N];
        work_buffer = temp_vla;
        /* Process temp_vla code here... */
        printf("Processed using Stack Allocation.\n");
    } else {
        /* Use Heap to safeguard Stack from crashing */
        work_buffer = malloc(N * sizeof(int));
        if (work_buffer == NULL) return;
        is_heap = 1;
        /* Process work_buffer code here... */
        printf("Processed using Heap Allocation.\n");
    }

    if (is_heap) {
        free(work_buffer);
    }
}

